import{_ as a,o as s,c as e,aw as t}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"EVM Quickstart","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"EVM Quickstart | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"getting-started/evm/quickstart.md","filePath":"getting-started/evm/quickstart.md","lastUpdated":1779882971000}');const l=a({name:"getting-started/evm/quickstart.md"},[["render",function(a,n,l,o,r,p){return s(),e("div",null,[...n[0]||(n[0]=[t('<h1 id="evm-quickstart" tabindex="-1">EVM Quickstart <a class="header-anchor" href="#evm-quickstart" aria-label="Permalink to &quot;EVM Quickstart&quot;">​</a></h1><p>Get an EVM rollup running locally in under 5 minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Go 1.22+</li><li>Docker</li><li>Git</li></ul><h2 id="_1-start-local-da" tabindex="-1">1. Start Local DA <a class="header-anchor" href="#_1-start-local-da" aria-label="Permalink to &quot;1. Start Local DA&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">go</span><span style="color:#BFF3C2;"> install</span><span style="color:#BFF3C2;"> github.com/evstack/ev-node/tools/local-da@latest</span></span>\n<span class="line"><span style="color:#94EEFF;">local-da</span></span></code></pre></div><p>You should see:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF Listening on host=localhost port=7980</span></span></code></pre></div><p>Keep this running in a separate terminal.</p><h2 id="_2-start-ev-reth" tabindex="-1">2. Start ev-reth <a class="header-anchor" href="#_2-start-ev-reth" aria-label="Permalink to &quot;2. Start ev-reth&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">git</span><span style="color:#BFF3C2;"> clone</span><span style="color:#BFF3C2;"> https://github.com/evstack/ev-reth.git</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ev-reth</span></span>\n<span class="line"><span style="color:#94EEFF;">docker</span><span style="color:#BFF3C2;"> compose</span><span style="color:#BFF3C2;"> up</span><span style="color:#FFECB6;"> -d</span></span></code></pre></div><p>This starts reth with Evolve&#39;s Engine API configuration. The default ports:</p><ul><li><code>8545</code> — JSON-RPC</li><li><code>8551</code> — Engine API</li></ul><h2 id="_3-start-ev-node" tabindex="-1">3. Start ev-node <a class="header-anchor" href="#_3-start-ev-node" aria-label="Permalink to &quot;3. Start ev-node&quot;">​</a></h2><p>In a new terminal:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">git</span><span style="color:#BFF3C2;"> clone</span><span style="color:#BFF3C2;"> https://github.com/evstack/ev-node.git</span></span>\n<span class="line"><span style="color:#94EEFF;">cd</span><span style="color:#BFF3C2;"> ev-node</span></span>\n<span class="line"><span style="color:#94EEFF;">make</span><span style="color:#BFF3C2;"> build-evm</span></span></code></pre></div><p>Initialize and start:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">./build/evm</span><span style="color:#BFF3C2;"> init</span><span style="color:#FFECB6;"> --evnode.node.aggregator</span><span style="color:#FFECB6;"> --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">./build/evm</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.block_time</span><span style="color:#BFF3C2;"> 1s</span></span></code></pre></div><p>You should see blocks being produced:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>INF block marked as DA included blockHeight=1</span></span>\n<span class="line"><span>INF block marked as DA included blockHeight=2</span></span></code></pre></div><h2 id="_4-connect-a-wallet" tabindex="-1">4. Connect a Wallet <a class="header-anchor" href="#_4-connect-a-wallet" aria-label="Permalink to &quot;4. Connect a Wallet&quot;">​</a></h2><p>Add the network to MetaMask:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Network Name</td><td>Evolve Local</td></tr><tr><td>RPC URL</td><td><a href="http://localhost:8545" target="_blank" rel="noreferrer">http://localhost:8545</a></td></tr><tr><td>Chain ID</td><td>1337</td></tr><tr><td>Currency</td><td>ETH</td></tr></tbody></table><h2 id="_5-deploy-a-contract" tabindex="-1">5. Deploy a Contract <a class="header-anchor" href="#_5-deploy-a-contract" aria-label="Permalink to &quot;5. Deploy a Contract&quot;">​</a></h2><p>With Foundry:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">forge</span><span style="color:#BFF3C2;"> create</span><span style="color:#BFF3C2;"> src/Counter.sol:Counter</span><span style="color:#FFECB6;"> --rpc-url</span><span style="color:#BFF3C2;"> http://localhost:8545</span><span style="color:#FFECB6;"> --private-key</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">YOUR_KE</span><span style="color:#DBD7CA;">Y</span><span style="color:#888888;">&gt;</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/getting-started/evm/setup-ev-reth">Configure ev-reth</a> — Customize chainspec, features</li><li><a href="/getting-started/evm/deploy-contracts">Deploy Contracts</a> — Foundry and Hardhat setup</li><li><a href="/ev-reth/features/sponsored-transactions">Sponsored Batch Transactions</a> — Sponsor user gas and batch app operations</li><li><a href="/ev-reth/js-client">JavaScript Client</a> — Build type <code>0x76</code> transactions from Viem</li><li><a href="/guides/da-layers/celestia">Connect to Celestia</a> — Production DA layer</li><li><a href="/guides/running-nodes/full-node">Run a Full Node</a> — Non-sequencer node setup</li></ul>',28)])])}]]);export{n as __pageData,l as default};
